// App-only (client credentials) — NÃO precisa refreshToken
// Lista e-mails do Graph /users + lista USUARIOS SharePoint
const cfg = $('Config Azure App (edite aqui)').first().json;
const tenant = cfg.MICROSOFT_TENANT_ID;
const clientId = cfg.MICROSOFT_CLIENT_ID;
const clientSecret = cfg.MICROSOFT_CLIENT_SECRET;

if (!tenant || !clientId || !clientSecret || clientSecret.includes('COLE_AQUI')) {
  throw new Error('Preencha MICROSOFT_CLIENT_SECRET no node "Config Azure App"');
}

const tokenRes = await this.helpers.httpRequest({
  method: 'POST',
  url: `https://login.microsoftonline.com/${tenant}/oauth2/v2.0/token`,
  headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
  body: [
    'client_id=' + encodeURIComponent(clientId),
    'client_secret=' + encodeURIComponent(clientSecret),
    'scope=' + encodeURIComponent('https://graph.microsoft.com/.default'),
    'grant_type=client_credentials',
  ].join('&'),
});

const token = tokenRes.access_token;
if (!token) throw new Error('Falha ao obter token app-only: ' + JSON.stringify(tokenRes));

const headers = { Authorization: `Bearer ${token}` };
const seen = new Map();

const add = (email, displayName = '') => {
  const e = String(email ?? '').trim().toLowerCase();
  if (!/@(?:bpplaw\.com\.br|bismarchipires\.com\.br)$/i.test(e)) return;
  if (!seen.has(e)) seen.set(e, displayName || e);
};

// 1) Graph /users
let next = 'https://graph.microsoft.com/v1.0/users?$select=id,displayName,mail,userPrincipalName&$top=999';
while (next) {
  const page = await this.helpers.httpRequest({ method: 'GET', url: next, headers });
  for (const u of page.value ?? []) {
    add(u.mail, u.displayName);
    add(u.userPrincipalName, u.displayName);
  }
  next = page['@odata.nextLink'] ?? null;
}

// 2) Lista USUARIOS (site BISMARCHIPIRES) — catálogo de e-mails
const bpSite = cfg.SHAREPOINT_BP_SITE_ID;
const usuariosList = cfg.SHAREPOINT_USUARIOS_LIST_ID;
if (bpSite && usuariosList) {
  let uNext = `https://graph.microsoft.com/v1.0/sites/${bpSite}/lists/${usuariosList}/items?expand=fields(select=Title,field_1)&$top=200`;
  while (uNext) {
    const page = await this.helpers.httpRequest({ method: 'GET', url: uNext, headers });
    for (const item of page.value ?? []) {
      const f = item.fields ?? {};
      add(f.field_1, f.Title);
    }
    uNext = page['@odata.nextLink'] ?? null;
  }
}

if (seen.size === 0) throw new Error('Nenhum e-mail @bpplaw/@bismarchipires encontrado');

return [...seen.entries()].map(([email, displayName]) => ({
  json: {
    email,
    displayName,
    logonName: `i:0#.f|membership|${email}`,
  },
}));

const body = $input.first().json.body ?? $input.first().json;
const email = String(body.email ?? '').trim().toLowerCase();
if (!email) throw new Error('Body JSON: { "email": "..." }');
if (!/@(?:bpplaw\.com\.br|bismarchipires\.com\.br)$/i.test(email)) {
  throw new Error('Domínio não permitido: ' + email);
}
return [{ json: { email, displayName: body.displayName ?? '', logonName: `i:0#.f|membership|${email}` } }];

const sp = $input.item.json;
const prev = $('Wait bootstrap').item.json;
const lookupId = sp?.Id ?? sp?.id;
return {
  json: {
    ok: Boolean(lookupId),
    email: prev.email,
    displayName: sp?.Title ?? prev.displayName ?? '',
    lookupId: lookupId ? String(lookupId) : null,
    error: lookupId ? null : (sp?.error?.message ?? sp?.message ?? JSON.stringify(sp).slice(0, 200)),
  },
};

const sp = $input.item.json;
const prev = $('Wait webhook').item.json;
const lookupId = sp?.Id ?? sp?.id;
return {
  json: {
    ok: Boolean(lookupId),
    email: prev.email,
    displayName: sp?.Title ?? prev.displayName ?? '',
    lookupId: lookupId ? String(lookupId) : null,
    error: lookupId ? null : (sp?.error?.message ?? sp?.message ?? JSON.stringify(sp).slice(0, 200)),
  },
};

const items = $input.all();
const map = {};
const add = (key, id) => {
  const k = String(key ?? '').trim().toLowerCase();
  if (k) map[k] = String(id);
};

let ok = 0;
let fail = 0;
for (const item of items) {
  const row = item.json;
  if (!row.ok || !row.lookupId) { fail++; continue; }
  ok++;
  add(row.email, row.lookupId);
  add(row.displayName, row.lookupId);
  if (row.email?.endsWith('@bismarchipires.com.br')) {
    add(row.email.replace('@bismarchipires.com.br', '@bpplaw.com.br'), row.lookupId);
  }
  if (row.email?.endsWith('@bpplaw.com.br')) {
    add(row.email.replace('@bpplaw.com.br', '@bismarchipires.com.br'), row.lookupId);
  }
}

return [{
  json: {
    key: 'sharepoint_person_lookups',
    value: JSON.stringify(map),
    updated_at: new Date().toISOString(),
    ok,
    fail,
    totalKeys: Object.keys(map).length,
  },
}];
